var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"REVELA_NPC_NULL_NULL","text":{"KOREA":"아까부터 계속 똑같아, 도련님. 정부군 놈들은 아무런 응답도 없어.","JPN":"さっきからずっと同じだぜ、坊ちゃん。政府軍の奴ら、なんの返事もねえよ。","ENG":"It’s still the same as earlier, young master. Those government guys aren’t responding at all.","TWN":"少爺，政府軍從剛剛就一直沒回應。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"REVELD_NPC_NULL_NULL","text":{"KOREA":"흐흐, 도련님 말 듣고 겁나서 바지에 실례라도 한 거 아냐?","JPN":"ふふ、坊ちゃんの話に怯えておもらしでもしたんじゃねえか？","ENG":"Ha, they probably just crapped their pants when they saw your message.","TWN":"呵呵，會不會是聽完少爺的話之後嚇到尿褲子啦？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELD_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"그래……. 저런 겁쟁이 놈들 때문에 우리 아버지가 돌아가신 거야.","JPN":"そう……あんな臆病者どものせいでおやじが死んだんだ。","ENG":"Yeah... And those cowards killed my father.","TWN":"嗯嗯……我爸爸就是被那些膽小鬼害死的！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"성명서 보내고 몇 분이나 지났지?","JPN":"声明書送ってからどのくらい経った？","ENG":"How long has it been since I sent the message?","TWN":"聲明影片傳過去後，現在過了幾分鐘？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"REVELA_NPC_NULL_NULL","text":{"KOREA":"10분 좀 넘었어.","JPN":"10分ぐらいだな。","ENG":"A little over 10 minutes.","TWN":"10分鐘左右。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELD_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"REVELA_NPC_NULL_NULL","text":{"KOREA":"뉴스에서는 축포라고 떠들던데, 중앙대로에 한 발 쏴 주면 녀석들도 반응하지 않을까?","JPN":"ニュースでは祝砲って騒いでるが、中央大通りに一発撃ってやれば奴らも反応するんじゃねえの？","ENG":"The news claimed our shot was just an artillery salute, but they will have to respond if we fire on the main street, right?","TWN":"新聞上說是禮炮，還是要朝中央大道射一發？這樣他們還不回應嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELD_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"헤, 헤헤, 그럴까?","JPN":"へ、へへ、そうしようか？","ENG":"Heh, heh heh... Then shall we?","TWN":"嘿嘿嘿，要嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"성대하게 한 발 날려 버리면, 저격수 나리도 날 보는 눈이 좀 바뀌려나……?","JPN":"盛大に一発飛ばせば、スナイパーの旦那が俺を見る目もちょっと変わるかな……？","ENG":"If we fire another magnificent shot, maybe it would change the way miss sniper looks at me...?","TWN":"這發射出去，狙擊手大姊對我會另眼相看嗎……？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"REVELA_NPC_NULL_NULL","text":{"KOREA":"뭐야, 도련님. 설마 그 약장수 여자애한테 관심 있어?","JPN":"なんだよ、坊ちゃん。まさかあの薬売りの女の子に興味あんの？","ENG":"What the... Are you interested in that drug dealer?","TWN":"哇～少爺，你該不會是對那個藥頭有興趣吧？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"REVELA_NPC_NULL_NULL","text":{"KOREA":"나는 그 친구라는 누님이 취향이던데, 흐흐.","JPN":"俺はあのお仲間だっていう姉ちゃんの方が好みだな、ふふ。","ENG":"Her friend, the sword fighter, is more my style, he he.","TWN":"我倒是對她那個朋友比較有興趣，嘿嘿。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"……그, 그렇지. 저격수 나리가 응원해 준 덕분에 나도 어깨에 힘 좀 들어갔으니까.","JPN":"……ま、まあな。スナイパーの旦那が応援してくれたおかげで俺も肩に力入ったしな。","ENG":"...Y-Yeah. Thanks to her praise I woke up feeling I want to flounce around.","TWN":"……嗯，多虧有她拉我一把，我才能抬頭挺胸。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"REVELC_NPC_NULL_NULL","text":{"KOREA":"오오, 누가 자크 대장님 아들내미 아니랄까 봐.","JPN":"おお、さすがジャック隊長の息子さんだな。","ENG":"Whoa, no wonder this is Captain Jacques’ son talking.","TWN":"喔喔，誰敢小看札克 隊長的兒子！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REVELD_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELC_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"REVELD_NPC_NULL_NULL","text":{"KOREA":"흐흐……. 뒈질 걱정하기 싫으니까 안 나오던 개소리가 참 잘도 나온다. 그치?","JPN":"ふふ……死ぬことの心配したくねえから、今まで出てこなかったデタラメがするする出てくる。なあ？","ENG":"He he... Not wanting to worry about being killed, we’re just letting everything out all at once.","TWN":"呵呵……狗被逼急也是會跳牆的，對吧？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REVELD_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELC_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"좋아! 한 발 더 장전해!","JPN":"よし！　もう一発こめろ！","ENG":"Yeah! Let’s fire again!","TWN":"好！再來一發！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"이 도시를 불바다로 만들어 버리자고!!","JPN":"この街を火の海にしちゃおうぜ！！","ENG":"Let’s turn this city into a sea of flames!!","TWN":"我要把這座城市變成一片火海！！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"REVELA_NPC_NULL_NULL","text":{"KOREA":"뭐지? 총소리인가?","JPN":"なんだ？　銃声か？","ENG":"What was that? Was that gunfire?","TWN":"怎麼回事？是槍聲？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELC_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"REVELC_NPC_NULL_NULL","text":{"KOREA":"차단기가 부서졌다! 어떤 놈이 바이크로 들이받았대!","JPN":"遮断機が壊れた！　誰かがバイクで衝突したって！","ENG":"The circuit breaker is broken! Someone smashed it with a motorcycle!","TWN":"斷路器發生故障！不知道是哪個傢伙騎摩托車撞進來！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELC_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"REVELD_NPC_NULL_NULL","text":{"KOREA":"바이크로? 대체 어떤 정신 나간 새끼야?","JPN":"バイクで？　一体どこのいかれた奴だよ？","ENG":"A motorcycle? What bastard is crazy enough to do that?","TWN":"摩托車？到底是哪個神經病？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELD_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"AGENT_GRONIA_WITH_BIKE","text":{"KOREA":"……나야. 유쾌한 약쟁이 친구들.","JPN":"……私よ。愉快な薬中毒者のみんな。","ENG":"...I am, my dear drug addict friends.","TWN":"……是我，歡樂的毒蟲們。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WITH_BIKE","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L35_1","type":"dialog","speaker":"AGENT_GRONIA_WITH_BIKE","text":{"KOREA":"안 본 지 오래돼서 걱정스러운데, 다들 건강하지?","JPN":"久々に会うから心配なんだけど、みんな元気？","ENG":"We haven’t seen each other for so long. How have you guys been?","TWN":"那麼久不見，大家都還好吧？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WITH_BIKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"너……! 아버지의 원수……!","JPN":"お前……！　おやじの仇……！","ENG":"You...! My father’s foe...!","TWN":"你……！我爸的仇人……！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WITH_BIKE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"어디서 뻔뻔하게 낯짝을 들이밀어? 우리가 호구로 보이냐?! 어!","JPN":"図々しく面を出しやがって、俺らをバカにしてんのか！　あん！？","ENG":"Why are you acting all cocky? Do we look like pushovers to you?! Hey!","TWN":"你竟然還有臉出現在我面前？當我們是塑膠嗎？！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WITH_BIKE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"AGENT_GRONIA_WITH_BIKE","text":{"KOREA":"우린 지금 전쟁 중이야. 원수라고 부르고 싶었으면 처음부터 무기를 들지 말았어야지.","JPN":"私たちは今戦争中よ。仇と呼びたければ最初から武器を取らないことね。","ENG":"We are at war. If you wanted to call me a foe, you shouldn't have taken up arms in the first place.","TWN":"我們現在可是在打仗，戰爭中不是你死就是我亡，哪有什麼仇人不仇人的。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WITH_BIKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"AGENT_GRONIA_WITH_BIKE","text":{"KOREA":"아니면 이 나라에서 태어나질 말았거나. 안 그래?","JPN":"それともこの国に生まれないとか。そうじゃない？","ENG":"Or you shouldn’t have been born in this country. Am I wrong?","TWN":"怪只能怪你出生在這個國家，不是嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WITH_BIKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"헤, 헤헤……! 그래, 그렇게 나오셔야지!!","JPN":"へ、へへ……！　そう、そう来なくっちゃな！","ENG":"Heh, heh heh... Fine, if that’s the way you want to play it!!","TWN":"嘿嘿嘿……！很好，你說得很對！！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WITH_BIKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"뭐하냐, 짜식들아! 정면에서 들이받았는데 우리도 제대로 상대해 줘야지!","JPN":"何してんだ、お前ら！　正面から衝突してきたんだ、俺らもちゃんと相手をしてやるぞ！","ENG":"What the hell are you doing standing around? She punched us right in the mouth, now we’ve got to do the same to her!","TWN":"還楞著幹嘛！！人家都已經打到你家裡來，我們當然要好好招待囉！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"}]`);export{e as default};